function resumeKey(month){const f=sourceFile;return`promo-v2-upload:${month}:${f?.name||'unknown'}:${f?.size||0}:${f?.lastModified||0}`}
function loadResume(month){try{return JSON.parse(localStorage.getItem(resumeKey(month))||'null')||{completed:[],attempts:{},updated_at:null}}catch{return{completed:[],attempts:{},updated_at:null}}}
function saveResume(month,state){state.updated_at=new Date().toISOString();localStorage.setItem(resumeKey(month),JSON.stringify(state))}
async function postBatch(cards,key,month){const started=performance.now(),r=await fetch(ENDPOINT,{method:'POST',headers:{'Content-Type':'application/json','x-promo-admin-key':key},body:JSON.stringify({action:'batch_upload',promo_month_id:month,cards:cards.map(it=>({file_name:it.fileName,data_url:it.dataUrl,benefit_text:it.detectedFunctionLabel,detected_function_label:it.detectedFunctionLabel,benefit_confidence:it.ocr.selected?.confidence||0,benefit_box:it.benefitBox,detection_status:it.detectionStatus,detection_method:'blue_grid_lock_v5_badge_template_two_stage'}))})}),j=await r.json();if(!r.ok||!j.ok)throw Error((j.error||'upload_failed')+(j.detail?': '+j.detail:''));return{...j,client_ms:Math.round(performance.now()-started)}}
async function postBatchWithRetry(cards,key,month,state,batchNo){let err;for(let attempt=1;attempt<=MAX_BATCH_ATTEMPTS;attempt++){state.attempts[batchNo]=(state.attempts[batchNo]||0)+1;saveResume(month,state);try{return await postBatch(cards,key,month)}catch(e){err=e;log(`Batch ${batchNo+1} ล้มเหลวครั้ง ${attempt}: ${e.message||e}`,'bad');if(attempt<MAX_BATCH_ATTEMPTS)await sleep(600*2**(attempt-1))}}throw err}
async function upload(){const key=$('key').value.trim(),month=$('month').value.trim().toUpperCase();if(!key)return alert('ใส่รหัสก่อน');if(items.length!==212)return alert('ต้องตรวจครบ 212 ใบก่อน');const up=items.filter(x=>x.uploadable);if(up.length!==212)return alert(`ยังมีรายการต้องตรวจ ${212-up.length} ใบ — V2 ไม่อัปโหลดข้อมูลไม่ครบ`);$('upload').disabled=true;const state=loadResume(month),completed=new Set(state.completed),pending=up.filter(x=>!completed.has(x.cardId)),batches=[];for(let i=0;i<pending.length;i+=BATCH_SIZE)batches.push(pending.slice(i,i+BATCH_SIZE));if(!batches.length){st('อัปโหลดครบแล้วจากสถานะ Resume');$('upload').disabled=false;return}let next=0,done=0,ok=completed.size,fail=0;const t0=performance.now();await Promise.all(Array.from({length:BATCH_CONCURRENCY},async()=>{while(true){const i=next++;if(i>=batches.length)return;const cards=batches[i];try{const j=await postBatchWithRetry(cards,key,month,state,i);for(const c of cards)completed.add(c.cardId);state.completed=[...completed];saveResume(month,state);ok=completed.size;log(`✓ Batch ${i+1}/${batches.length}: ${j.uploaded} ใบ | retry ${state.attempts[i]-1} | server ${j.total_ms} ms`,'ok')}catch(e){fail+=cards.length;log(`✗ Batch ${i+1} ค้าง ${cards.length} ใบ: ${e.message||e}`,'bad')}done++;bar(done,batches.length)}}));st(`อัปโหลด/Resume ${ok}/212 | ค้าง ${fail} | ${((performance.now()-t0)/1000).toFixed(1)} วินาที`);$('upload').disabled=false}
